#include <iostream>

int total_alive_counters = 0;

class Counter {
public:
    Counter() {
        total_alive_counters++;
    }

    Counter(const Counter& other) {
        total_alive_counters++;
    }

    ~Counter() {
        total_alive_counters--;
    }

    Counter& operator=(const Counter& other) {
        return *this;
    }

    static int getCount() {
        return total_alive_counters;
    }
};

int main() {
    std::cout << "Initial count: " << Counter::getCount() << std::endl;

    {
        Counter c1;
        std::cout << "After creating c1: " << Counter::getCount() << std::endl;

        Counter c2;
        std::cout << "After creating c2: " << Counter::getCount() << std::endl;

        Counter c3 = c1;
        std::cout << "After copying c1 to c3: " << Counter::getCount() << std::endl;

        Counter c4;
        std::cout << "After creating c4: " << Counter::getCount() << std::endl;
    }

    std::cout << "After block ends: " << Counter::getCount() << std::endl;

    Counter* p_c5 = new Counter();
    std::cout << "After creating c5 (heap): " << Counter::getCount() << std::endl;
    delete p_c5;
    std::cout << "After deleting c5 (heap): " << Counter::getCount() << std::endl;

    return 0;
}
